optimized_federated_query:
# Smart Federated Query with UNION for Multiple Class Interpretations
# Each UNION branch uses different endpoints or predicates

SELECT ?drug ?id ?keggDrug ?title
WHERE {
  # Scenario 1: ?title=Literal, ?keggDrug=Enzyme
  {
    SERVICE <http://localhost:8892/sparql/> {
      ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/drugCategory> <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugcategory/micronutrient> .
      ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/casRegistryNumber> ?id .
    }
    SERVICE <http://localhost:8895/sparql/> {
      ?keggDrug <http://purl.org/dc/elements/1.1/title> ?title . # ?keggDrug:Enzyme, ?title:Literal
      ?keggDrug <http://www.w3.org/1999/02/22-rdf-syntax-ns#type> <http://bio2rdf.org/ns/kegg#Drug> .
      ?keggDrug <http://bio2rdf.org/ns/bio2rdf#xRef> ?id .
    }
  }

  UNION

  # Scenario 2: ?title=Literal, ?keggDrug=Record
  {
    SERVICE <http://localhost:8890/sparql/> {
      ?keggDrug <http://bio2rdf.org/ns/bio2rdf#xRef> ?id .
    }
    SERVICE <http://localhost:8892/sparql/> {
      ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/drugCategory> <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugcategory/micronutrient> .
      ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/casRegistryNumber> ?id .
    }
    SERVICE <http://localhost:8894/sparql/> {
      ?keggDrug <http://purl.org/dc/elements/1.1/title> ?title . # ?keggDrug:Record, ?title:Literal
    }
    SERVICE <http://localhost:8899/sparql/> {
      ?keggDrug <http://www.w3.org/1999/02/22-rdf-syntax-ns#type> <http://bio2rdf.org/ns/kegg#Drug> .
    }
  }
}
LIMIT 1000
